// ===================================================
// WF-APPROVE Step 1: NocoDB Webhook 바디 파싱
// NocoDB Webhook 이벤트에서 파트너 신청 정보 추출
// After Update 이벤트: data 객체 내에 필드 존재
// ===================================================

const input = $input.first().json;

// NocoDB Webhook 페이로드 구조:
// { type: 'records.after.update', data: { rows: [...], previous_rows: [...] } }
// 또는 직접 body에 필드가 있을 수 있음 (설정에 따라 다름)
const body = input.body || input;

// NocoDB Webhook rows 배열에서 첫 번째 레코드 추출
let record = {};
if (body.data && body.data.rows && body.data.rows.length > 0) {
  record = body.data.rows[0];
} else if (body.rows && body.rows.length > 0) {
  record = body.rows[0];
} else {
  // 직접 필드가 있는 경우 (구버전 NocoDB)
  record = body;
}

// === status 필드 확인 (approved일 때만 처리) ===
const status = String(record.status || '').toLowerCase().trim();

if (status !== 'approved') {
  return [{
    json: {
      _skip: true,
      _skipReason: 'status가 approved가 아님: ' + status,
      _timestamp: new Date().toISOString()
    }
  }];
}

// === 필드 추출 ===
const memberId = String(record.member_id || '').trim();
const applicantName = String(record.name || record.applicant_name || '').trim();
const studioName = String(record.studio_name || record.workshop_name || '').trim();
const email = String(record.email || '').trim();
const specialty = String(record.specialty || '').trim();
const phone = String(record.phone || '').trim();
const location = String(record.location || '').trim();

if (!memberId) {
  return [{
    json: {
      _skip: true,
      _skipReason: 'member_id 누락',
      _timestamp: new Date().toISOString()
    }
  }];
}

return [{
  json: {
    _skip: false,
    _memberId: memberId,
    _name: applicantName,
    _studioName: studioName,
    _email: email,
    _specialty: specialty,
    _phone: phone,
    _location: location,
    _timestamp: new Date().toISOString()
  }
}];

// ===================================================
// WF-APPROVE Step 3a: WF-08 성공 응답 처리
// ===================================================

const wf08Result = $input.first().json;
const prevData = $('Parse NocoDB Webhook').first().json;

const success = wf08Result.success === true;
const partnerCode = (wf08Result.data && wf08Result.data.partner_code) || '(코드 확인 필요)';
const partnerName = (wf08Result.data && wf08Result.data.partner_name) || prevData._studioName || prevData._name;

let message;
if (success) {
  message = '[NocoDB 자동 승인 완료]\n\n'
    + '파트너명: ' + partnerName + '\n'
    + '회원ID: ' + prevData._memberId + '\n'
    + '파트너 코드: ' + partnerCode + '\n'
    + '처리 방식: NocoDB GUI 상태 변경 → 자동 승인\n'
    + '처리 시각: ' + new Date().toISOString();
} else {
  const errorMsg = (wf08Result.error && wf08Result.error.message) || JSON.stringify(wf08Result).substring(0, 200);
  message = '[NocoDB 자동 승인 실패]\n\n'
    + '회원ID: ' + prevData._memberId + '\n'
    + '오류: ' + errorMsg + '\n'
    + '처리 시각: ' + new Date().toISOString();
}

return [{
  json: {
    _success: success,
    _telegramMessage: message,
    _partnerCode: partnerCode,
    _memberId: prevData._memberId
  }
}];

// ===================================================
// WF-APPROVE Step 3b: WF-08 호출 자체 실패 처리
// (네트워크 오류, 타임아웃 등)
// ===================================================

const error = $input.first().json;
const prevData = $('Parse NocoDB Webhook').first().json;

const message = '[NocoDB 자동 승인 오류]\n\n'
  + '회원ID: ' + prevData._memberId + '\n'
  + '원인: WF-08 호출 실패 (네트워크/타임아웃)\n'
  + '오류: ' + JSON.stringify(error).substring(0, 300) + '\n'
  + '조치: NocoDB tbl_Applications에서 해당 신청을 직접 확인하고\n'
  + '      /webhook/partner-approve를 수동 호출해주세요\n'
  + '처리 시각: ' + new Date().toISOString();

return [{
  json: {
    _success: false,
    _telegramMessage: message,
    _memberId: prevData._memberId
  }
}];
